#!/bin/bash
# MoAI ConfigChange Hook Wrapper - Generated by moai-adk

temp_file=$(mktemp)
trap 'rm -f "$temp_file"' EXIT

# Read stdin with size limit (max 1MB)
MAX_SIZE=1048576
head -c "$MAX_SIZE" > "$temp_file"

# Skip if empty
if [ ! -s "$temp_file" ]; then
    exit 0
fi

# Try moai command in PATH
if command -v moai &> /dev/null; then
    exec moai hook config-change < "$temp_file" 2>/dev/null
fi


# Try detected Go bin path from initialization
if [ -f "/Users/goos/go/bin/moai" ]; then
    exec "/Users/goos/go/bin/moai" hook config-change < "$temp_file" 2>/dev/null
fi

# Try default ~/go/bin/moai
if [ -f "$HOME/go/bin/moai" ]; then
    exec "$HOME/go/bin/moai" hook config-change < "$temp_file" 2>/dev/null
fi

# Not found - exit silently
exit 0
